                    APIQuery q = new APIQuery(apname, path, si);
                    APIEntry ae = q.getAPIEntry(Encoder.parseInt(nodeId));
                    final String title = ae.getTitle();

                    final RagicDateFormatter apDateFormat=com.ragic.s3.util.Util.getDisplayDateTimeFormat(apname, true, bundle);
                    Path archiveRoot = Paths.get("cust", "data", apname, "archive", "history");
                    List<String[]> csvLines = new ArrayList<>();
